1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Simplest case ---
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const input = {
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    };
11	    const output = runScenario(input);
12	    expect(output).toEqual({ results: [{ premium: 5 }] });
13	  });
14	
15	  // --- Base premiums for main items (with 5G fee, no other modifiers, customer is newcomer with first contract → 10% first-insurance surcharge applies) ---
16	  // To isolate base premium tests, we use a long-standing customer's follow-up contract? Actually simpler: use 0 years + first contract = first insurance surcharge applies.
17	  // Let's add tests for each item type as single-item quotes with surcharges applied.
18	  it.todo("single sword (steel, enchantment 3, not cursed), newcomer, first contract → 100 base + 10 first-insurance + 5 fee = 115 G");
19	  it.todo("single amulet (silver, enchantment 2, not cursed), newcomer, first contract → 60 + 6 + 5 = 71 G");
20	  it.todo("single staff (wood, enchantment 1, not cursed), newcomer, first contract → 80 + 8 + 5 = 93 G");
21	  it.todo("single potion (glass, not cursed), newcomer, first contract → 40 + 4 + 5 = 49 G");
22	
23	  // --- Components (runes, moonstones) ---
24	  it.todo("1 rune, newcomer, first contract → 25 + 2.5 + 5 = 33 G (rounded up)");
25	  it.todo("2 runes → 50 G base premium (no block)");
26	  it.todo("3 runes → 60 G base premium (block applies)");
27	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
28	  it.todo("7 runes → 175 G base premium (no block — 7 not multiple of 3 nor exactly 3)");
29	
30	  // --- Alike components clarification (❓) ---
31	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
32	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
33	
34	  // --- Cursed surcharge ---
35	  it.todo("cursed sword (steel, enchantment 3), newcomer, first contract → 100 + 50 curse + 10 first = 160 + 5 fee = 165 G");
36	
37	  // --- High enchantment surcharge ---
38	  it.todo("sword enchantment 5 (not cursed), newcomer, first contract → 100 + 30 + 10 = 140 + 5 = 145 G (enchantment exactly 5 triggers surcharge)");
39	  it.todo("sword enchantment 4 (not cursed), newcomer, first contract → 100 + 10 = 110 + 5 = 115 G (no high-enchantment surcharge)");
40	  it.todo("cursed sword enchantment 5, newcomer, first contract → 100 + 50 + 30 + 10 = 190 + 5 = 195 G (both surcharges apply)");
41	
42	  // --- Loyalty discount threshold ---
43	  it.todo("customer with exactly 2 years, single sword, first contract → 100 - 20 loyalty + 10 first = 90 + 5 = 95 G");
44	
45	  // --- Modifier scope on multi-item policies ---
46	  it.todo("policy with cursed sword + plain amulet, newcomer, first contract → 100 + 60 + 50 curse + 16 first = 226 + 5 = 231 G");
47	
48	  // --- Rounding in MHPCO favor (premium rounds up) ---
49	  it.todo("premium calculation yielding 197.5 → final premium 198 G (rounded up)");
50	
51	  // --- Integration example: newcomer with cursed sword ---
52	  it.todo("newcomer (0 years), cursed sword (steel, enchantment 3), first contract → 165 G");
53	
54	  // --- Integration example: long-standing customer's second contract ---
55	  it.todo("3-year customer's second quote: cursed sword enchantment 7 → 160 G");
56	
57	  // --- First-insurance applies per item, even on follow-up contract (❓) ---
58	  it.todo("follow-up contract still gets first-insurance surcharge per item (clarification from integration example)");
59	
60	  // --- Claims: standard reimbursement ---
61	  it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400 (500 - 100 deductible)");
62	  it.todo("rune damage 200 → payout 100 (no special clause; 200 - 100 deductible)");
63	
64	  // --- Claims: dragon material ---
65	  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (full reimbursement minus deductible)");
66	
67	  // --- Claims: high enchantment (≥8) ---
68	  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");
69	
70	  // --- Claims: dragon material AND enchantment ≥ 8 (50% wins) ---
71	  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% wins, then deductible)");
72	  it.todo("dragon-material sword, enchantment exactly 8, damage 1000 → payout 400 (high-enchantment clause applies, then deductible)");
73	
74	  // --- Claims: deductible per damage event (per item) ---
75	  it.todo("dragon attack damaging sword 500 + amulet 300 → payout 600 (deductible applies per item: 400 + 200)");
76	
77	  // --- Claims: cap = 2x insurance sum ---
78	  it.todo("policy covering sword + amulet → insurance sum 1600 G, cap 3200 G");
79	  it.todo("cursed sword (insurance value 1000) → cap 2000 G (cap based on unmodified value)");
80	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount doesn't affect sum)");
81	
82	  // --- Cap exhaustion across multiple claims ---
83	  it.todo("sword (cap 2000), claim 1 of 1500 → payout 1400, remainingCap 600");
84	  it.todo("sword (cap 2000), claim 1 of 1500 then claim 2 of 1500 → payout 1400 then 600, remainingCap 600 then 0");
85	
86	  // --- Rounding payout down (MHPCO favor) ---
87	  it.todo("payout calculation yielding 350.5 → final payout 350 G (rounded down)");
88	
89	  // --- Multiple items of same type (❓) ---
90	  it.todo("policy with two swords → insurance sum 2000, cap 4000");
91	  it.todo("dragon attack damages both swords (two damage entries) → each gets its own deductible");
92	
93	  // --- Error cases ---
94	  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero, error to stderr");
95	  it.todo("claim references damage item not part of policy → CLI exits non-zero");
96	  it.todo("damages contains more entries of a type than policy covers → claim rejected, CLI exits non-zero");
97	  it.todo("claim with negative damage amount → CLI exits non-zero");
98	});
